import React, { useEffect, useState } from 'react';
import { deleteProduct } from '../../../services/productService';
import api from '../../../services/api';
import toast from 'react-hot-toast';

const Products = () => {

  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const res = await api.get('/admin/products');
      const data = res.data;
      setProducts(Array.isArray(data) ? data : (data?.products || []));
    } catch (err) {
      toast.error('Failed to load products');
      setProducts([]);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await api.delete(`/admin/products/${id}`);
      toast.success('Product deleted');
      loadProducts();
    } catch (err) {
      toast.error('Failed to delete product');
    }
  };

  return (
    <div>
      <div className="admin-header">
        <h1>Manage Products</h1>
        <button className="btn btn-primary" onClick={() => window.location.href = '/admin/products/new'}>+ Create Product</button>
      </div>

      {loading ? (
        <div className="loader" />
      ) : (
        <div style={{overflowX: 'auto'}}>
          <table className="admin-table">
            <thead>
              <tr>
                <th>Product Name</th>
                <th>Price</th>
                <th>Stock</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {products.map(p => (
                <tr key={p._id}>
                  <td>{p.name}</td>
                  <td>₹{p.price}</td>
                  <td>{p.countInStock ?? p.stock ?? '-'}</td>
                  <td>
                    <span className={`status-badge ${p.isActive ? 'active' : 'inactive'}`}>
                      {p.isActive ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td>
                    <div className="admin-actions">
                      <button 
                        className="admin-btn admin-btn-edit" 
                        onClick={() => window.location.href = `/admin/products/${p._id}/edit`}
                      >
                        Edit
                      </button>
                      <button 
                        className="admin-btn admin-btn-delete" 
                        onClick={() => handleDelete(p._id)}
                      >
                        Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default Products;
